const item = items[0].json;

// O Airtable SEMPRE retorna um campo "id" no nível raiz + "fields" com os dados
const id = item.id ?? null;
const dados = item.fields ?? item;

if (!dados || typeof dados !== 'object') {
  throw new Error("Não foram encontrados dados válidos para processar.");
}

// Cria objeto com os dados originais (separados e formatados em snake_case)
const dadosSeparados = {};
for (const [chave, valor] of Object.entries(dados)) {
  const chaveFormatada = chave
    .replace(/ /g, '_')     // Substitui espaços por underscore
    .replace(/-/g, '_')     // Substitui traços por underscore
    .toLowerCase();         // Tudo em minúsculo
  dadosSeparados[chaveFormatada] = valor;
}

// Cria também versão formatada para AI Agent
const linhas = Object.entries(dados).map(([chave, valor]) => {
  const chaveFormatada = chave
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase());
  return `**${chaveFormatada}:** ${valor}`;
});

const mensagemFinal = `📝 Aqui estão os dados do lead:\n\n${linhas.join('\n')}`;

return [
  {
    json: {
      id,                  // 🔑 ID do registro Airtable (fundamental para update)
      ...dadosSeparados,   // Campos separados
      userMessage: mensagemFinal // Texto completo opcional
    }
  }
];

