= {{(() => {
  const msg = $('webhook_wpp').item.json.body.data.message;
  // Text message
  if (msg.conversation) return msg.conversation;
  // Reaction emoji
  if (msg.reactionMessage && msg.reactionMessage.text) return msg.reactionMessage.text;
  // Caption from image, video or document
  if (msg.imageMessage && msg.imageMessage.caption) return msg.imageMessage.caption;
  if (msg.videoMessage && msg.videoMessage.caption) return msg.videoMessage.caption;
  if (msg.documentMessage && msg.documentMessage.caption) return msg.documentMessage.caption;
  // Extended text
  if (msg.extendedTextMessage && msg.extendedTextMessage.text) return msg.extendedTextMessage.text;
  // Audio transcription (caso use algum serviço)
  if (msg.audioMessage && msg.audioMessage.transcription) return msg.audioMessage.transcription;
  // Outros casos customizados
  return '';
})()}}

